def fib(n: int, memo: dict = None) -> int:
    # Initialize the dictionary on the first call
    if memo is None:
        memo = {}

    # Base cases
    if n == 0:
        return 0
    if n == 1:
        return 1

    # Check if value is already in the dictionary
    if n in memo:
        return memo[n]

    # Recursive step with storage
    memo[n] = fib(n - 1, memo) + fib(n - 2, memo)
    return memo[n]

